# Jelly Squeeze

GSAP Draggable element that plays a 215-frame image sequence as the user drags, creating a tactile jelly squish animation with elastic spring-back on release.

## Use when
- Injecting playful brand personality into a landing page or product hero.
- Creating interactive demos that reward cursor engagement with delightful feedback.
- Drawing attention to a CTA through unexpected micro-interaction.

## Stack
- Framework: react
- Libraries: gsap (with Draggable plugin)

## Install
```bash
npm install gsap
```

## Component — jelly-squeeze.tsx
```tsx
import React, { useEffect, useRef, useState } from 'react';
import { gsap } from 'gsap';
import { Draggable } from 'gsap/Draggable';

gsap.registerPlugin(Draggable);

const FRAME_COUNT = 215;
const BASE_URL = 'https://cerpow.github.io/cerpow-img/jelly/';

export interface JellySqueezeProps {
  className?: string;
  size?: number;
}

export const JellySqueeze: React.FC<JellySqueezeProps> = ({
  className = '',
  size = 200
}) => {
  const containerRef = useRef<HTMLDivElement>(null);
  const imgRef = useRef<HTMLImageElement>(null);
  const frameRef = useRef(0);

  useEffect(() => {
    if (!containerRef.current || !imgRef.current) return;

    // Preload frames
    for (let i = 1; i <= FRAME_COUNT; i++) {
      const img = new Image();
      img.src = `${BASE_URL}${String(i).padStart(4, '0')}.webp`;
    }

    let dragging = false;
    let lastX = 0;

    const draggable = Draggable.create(containerRef.current, {
      type: 'x,y',
      onDragStart() {
        dragging = true;
        lastX = this.x;
      },
      onDrag() {
        const delta = Math.abs(this.x - lastX);
        frameRef.current = Math.min(
          FRAME_COUNT - 1,
          frameRef.current + Math.round(delta * 0.5)
        );
        if (imgRef.current) {
          imgRef.current.src = `${BASE_URL}${String(frameRef.current + 1).padStart(4, '0')}.webp`;
        }
        lastX = this.x;
      },
      onDragEnd() {
        dragging = false;
        gsap.to(containerRef.current, {
          x: 0,
          y: 0,
          duration: 1.5,
          ease: 'elastic.out(1, 0.3)'
        });
        gsap.to(frameRef, {
          current: 0,
          duration: 0.5,
          ease: 'power2.in',
          onUpdate() {
            if (imgRef.current) {
              const f = Math.max(0, Math.round(frameRef.current));
              imgRef.current.src = `${BASE_URL}${String(f + 1).padStart(4, '0')}.webp`;
            }
          }
        });
      }
    })[0];

    return () => {
      draggable.kill();
    };
  }, []);

  return (
    <div
      ref={containerRef}
      className={`cursor-grab active:cursor-grabbing select-none ${className}`}
      style={{ width: size, height: size }}
    >
      <img
        ref={imgRef}
        src={`${BASE_URL}0001.webp`}
        alt="Jelly squeeze animation"
        style={{ width: size, height: size, objectFit: 'contain' }}
        draggable={false}
      />
    </div>
  );
};

export default JellySqueeze;
```

## Demo
```tsx
import React from 'react';
import JellySqueeze from './Component';

export default function App() {
  return (
    <div className="w-full h-screen bg-[#F9F9F9] flex items-center justify-center">
      <div className="flex flex-col items-center gap-4">
        <JellySqueeze size={300} />
        <p className="text-gray-500 text-sm">Drag me!</p>
      </div>
    </div>
  );
}
```

## Notes
- Loads 215 external WebP images from `https://cerpow.github.io/cerpow-img/jelly/`. Requires internet access; preloading all frames may consume significant bandwidth.
- Complexity is `heavy` due to GSAP Draggable plugin and large external asset set.
